class Solution:
    def findBridges(self, n: int, edges: list[list[int]]) -> str:
        graph = [[] for _ in range(n)]
        low = [n for _ in range(n)]
        disc = [n for _ in range(n)]
        parent = [-1 for _ in range(n)]
        time = 0

        def dfs(v):
            disc[v] = time
            low[v] = time
            time += 1
            for u in graph[v]:
                if disc[u] == n:
                    parent[u] = v
                    dfs(u)
                    low[v] = min(low[v], low[u])
                elif parent[v] != u:
                    low[v] = min(low[v], disc[u])

        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        for i in range(n):
            if parent[i] == -1: dfs(i)

        bridges = 0
        for i in range(n):
            if low[i] == disc[i]: bridges += 1

        if any(disc[i] < n for i in range(n)):
            return 'Cycle detected'
        return str(bridges)

