class Solution {
public:
    string findBridges(int n, vector<vector<int>>& edges) {
        vector<vector<int>> graph(n);
        vector<int> low(n, n);
        vector<int> disc(n, n);
        vector<int> parent(n, -1);
        int time = 0;

        function<void(int)> dfs = [&](int v) {
            disc[v] = time;
            low[v] = time;
            ++time;
            for (int u : graph[v]) {
                if (disc[u] == n) {
                    parent[u] = v;
                    dfs(u);
                    low[v] = min(low[v], low[u]);
                } else if (parent[v] != u) {
                    low[v] = min(low[v], disc[u]);
                }
            }
        };

        for (auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
            graph[edge[1]].push_back(edge[0]);
        }

        for (int i = 0; i < n; ++i) {
            if (parent[i] == -1) dfs(i);
        }

        int bridges = 0;
        for (int i = 0; i < n; ++i) {
            if (low[i] == disc[i]) bridges++;
        }

        if (any(disc[i] < n for int i : 0 ... n)) return "Cycle detected";
        return to_string(bridges);
    }
};
int main() {
    int n; cin >> n;
    vector<vector<int>> edges(n);
    for (int i = 0; i < n; ++i) {
        int u, v; cin >> u >> v; --u; --v;
        edges[u].push_back(v);
        edges[v].push_back(u);
    }
    Solution s;
    cout << s.findBridges(n, edges) << endl;
    return 0;
}
